  1	import { type FC, useMemo } from 'react';
  2	import { Controller, useWatch } from 'react-hook-form';
  3	
  4	import { FormGroupWithHelpText } from '@components/common/FormGroupWithHelpText/FormGroupWithHelpText';
  5	import { HelpIconPopover } from '@components/common/HelpIconPopover/HelpIconPopover';
  6	import { Alert, AlertVariant, Stack, StackItem, TextInput } from '@patternfly/react-core';
  7	import { isEmpty } from '@utils/helpers';
  8	import { useForkliftTranslation } from '@utils/i18n';
  9	
 10	import { useCreatePlanFormContext } from '../../hooks/useCreatePlanFormContext';
 11	import { useCreatePlanWizardContext } from '../../hooks/useCreatePlanWizardContext';
 12	import { useInitializeMappings } from '../../hooks/useInitializeMappings';
 13	import { GeneralFormFieldId } from '../general-information/constants';
 14	import { VmFormFieldId } from '../virtual-machines/constants';
 15	
 16	import {
 17	  defaultNetMapping,
 18	  netMapFieldLabels,
 19	  NetworkMapFieldId,
 20	  type NetworkMapping,
 21	} from './constants';
 22	import NetworkMapFieldTable from './NetworkMapFieldTable';
 23	import { filterTargetNetworksByProject, getSourceNetworkValues } from './utils';
 24	
 25	const NewNetworkMapFields: FC = () => {
 26	  const { t } = useForkliftTranslation();
 27	  const { control, getFieldState } = useCreatePlanFormContext();
 28	  const { network } = useCreatePlanWizardContext();
 29	  const [targetProject, vms, networkMap] = useWatch({
 30	    control,
 31	    name: [GeneralFormFieldId.TargetProject, VmFormFieldId.Vms, NetworkMapFieldId.NetworkMap],
 32	  });
 33	
 34	  const [availableSourceNetworks, sourceNetworksLoading, sourceNetworksError] = network.sources;
 35	  const [availableTargetNetworks, targetNetworksLoading, targetNetworksError] = network.targets;
 36	  const [oVirtNicProfiles, oVirtNicProfilesLoading, oVirtNicProfilesError] =
 37	    network.oVirtNicProfiles;
 38	  const isLoading = sourceNetworksLoading || targetNetworksLoading || oVirtNicProfilesLoading;
 39	  const { error } = getFieldState(NetworkMapFieldId.NetworkMap);
 40	
 41	  const { other: otherSourceNetworks, used: usedSourceNetworks } = getSourceNetworkValues(
 42	    availableSourceNetworks,
 43	    Object.values(vms),
 44	    oVirtNicProfiles,
 45	  );
 46	
 47	  const targetNetworkMap = useMemo(
 48	    () => filterTargetNetworksByProject(availableTargetNetworks, targetProject),
 49	    [availableTargetNetworks, targetProject],
 50	  );
 51	
 52	  useInitializeMappings<NetworkMapping>({
 53	    currentMap: networkMap,
 54	    defaultTarget: defaultNetMapping[NetworkMapFieldId.TargetNetwork],
 55	    fieldIds: {
 56	      mapField: NetworkMapFieldId.NetworkMap,
 57	      sourceField: NetworkMapFieldId.SourceNetwork,
 58	      targetField: NetworkMapFieldId.TargetNetwork,
 59	    },
 60	    isLoading,
 61	    usedSources: usedSourceNetworks,
 62	  });
 63	
 64	  return (
 65	    <Stack hasGutter className="pf-v6-u-ml-lg">
 66	      {error?.root && <Alert variant={AlertVariant.danger} isInline title={error.root.message} />}
 67	
 68	      {isEmpty(usedSourceNetworks) && !sourceNetworksLoading && (
 69	        <Alert
 70	          variant={AlertVariant.warning}
 71	          isInline
 72	          title={t('No source networks are available for the selected VMs.')}
 73	        />
 74	      )}
 75	
 76	      <NetworkMapFieldTable
 77	        networkMap={networkMap}
 78	        vms={vms}
 79	        oVirtNicProfiles={oVirtNicProfiles}
 80	        targetNetworks={targetNetworkMap}
 81	        usedSourceNetworks={usedSourceNetworks}
 82	        otherSourceNetworks={otherSourceNetworks}
 83	        isLoading={isLoading}
 84	        loadError={sourceNetworksError ?? targetNetworksError ?? oVirtNicProfilesError}
 85	      />
 86	
 87	      <FormGroupWithHelpText
 88	        label={netMapFieldLabels[NetworkMapFieldId.NetworkMapName]}
 89	        helperText={t("Provide a name now, or we'll generate one when the map is created.")}
 90	        labelIcon={
 91	          <HelpIconPopover>
 92	            <Stack hasGutter>
 93	              <StackItem>
 94	                {t(
 95	                  'Your selected network mappings will automatically save as a network map when your plan is created.',
 96	                )}
 97	              </StackItem>
 98	              <StackItem>
 99	                {t(
100	                  "Provide a name now, or we'll generate one when the map is created. You can find your network maps under the Network maps page.",
101	                )}
102	              </StackItem>
103	            </Stack>
104	          </HelpIconPopover>
105	        }
106	      >
107	        <Controller
108	          name={NetworkMapFieldId.NetworkMapName}
109	          control={control}
110	          render={({ field }) => <TextInput {...field} />}
111	        />
112	      </FormGroupWithHelpText>
113	    </Stack>
114	  );
115	};
116	
117	export default NewNetworkMapFields;

